package core.org.apache.accumulo.core.iterators.user;

public class AgeOffFilter extends Filter { private static final String TTL = "ttl" ; private static final String CURRENT_TIME = "currentTime" ; private long threshold ; private long currentTime ; @ Override public boolean accept ( Key k , Value v ) { if ( currentTime - k . getTimestamp ( ) > threshold ) return false ; return true ; } @ Override public void init ( SortedKeyValueIterator < Key , Value > source , Map < String , String > options , IteratorEnvironment env ) throws IOException { if ( options == null ) throw new IllegalArgumentException ( TTL + " must be set for AgeOffFilter" ) ; String ttl = options . get ( TTL ) ; if ( ttl == null ) throw new IllegalArgumentException ( TTL + " must be set for AgeOffFilter" ) ; super . init ( source , options , env ) ; threshold = Long . parseLong ( ttl ) ; String time = options . get ( CURRENT_TIME ) ; if ( time != null ) currentTime = Long . parseLong ( time ) ; else currentTime = System . currentTimeMillis ( ) ; } @ Override public SortedKeyValueIterator < Key , Value > deepCopy ( IteratorEnvironment env ) { AgeOffFilter copy = ( AgeOffFilter ) super . deepCopy ( env ) ; copy . currentTime = currentTime ; copy . threshold = threshold ; return copy ; } @ Override public IteratorOptions describeOptions ( ) { IteratorOptions io = super . describeOptions ( ) ; io . addNamedOption ( TTL , "time to live (milliseconds)" ) ; io . addNamedOption ( CURRENT_TIME , "if set, use the given value as the absolute time in milliseconds as the current time of day" ) ; io . setName ( "ageoff" ) ; io . setDescription ( "AgeOffFilter removes entries with timestamps more than <ttl> milliseconds old" ) ; return io ; } @ Override public boolean validateOptions ( Map < String , String > options ) { if ( super . validateOptions ( options ) == false ) return false ; try { Long . parseLong ( options . get ( TTL ) ) ; } catch ( Exception e ) { throw new IllegalArgumentException ( "bad long " + TTL + ":" + options . get ( TTL ) ) ; } return true ; } public static void setTTL ( IteratorSetting is , Long ttl ) { is . addOption ( TTL , Long . toString ( ttl ) ) ; } public static void setCurrentTime ( IteratorSetting is , Long currentTime ) { is . addOption ( CURRENT_TIME , Long . toString ( currentTime ) ) ; } }